Téléchargement






       {% sql {
  "query" : "select name as Name, Description, STRFTIME('%d/%m/%Y',date(date)) date_maj ,Web from Resources where Type='CodeSystem' and (url  like '%NOS%' or id  like 'tre-%')   and  json_extract(Resources.json,'$.status') != 'retired'  order by substr(name,5,1), abs(substr(name,6, instr(substr(name,6,4),'_' )-1))  ",
  "class" : "codes",
  "columns" : [
    { "name" : "Name", "type" : "link", "source" : "Name", "target" : "Web"},
    { "name" : "Description", "type" : "markdown", "source" : "Description"},
    { "name" : "Date MAJ", "type" : "markdown", "source" : "date_maj"}
  ]
} %}
